// src/pages/LandingPage.js

import React from "react";
import { useAuth } from "../context/AuthContext";

const LandingPage = () => {
  const { currentUser } = useAuth(); // Get the current user from context

  return (
    <div style={{ textAlign: "center", padding: "50px" }}>
      <h1>Welcome to Materii Opționale UVT</h1>
      {currentUser && (
        <h2>Hello, {currentUser.email}!</h2>
      )}
      <p>
        Here you can explore optional subjects, take quizzes to find the right courses for you, and manage your enrollment.
      </p>
      <p>
        Use the navigation to get started:
      </p>
      <ul style={{ listStyleType: "none", padding: 0 }}>
        <li><a href="/subjects">View Optional Subjects</a></li>
        <li><a href="/quizzes">Take a Quiz</a></li>
        <li><a href="/profile">Your Profile</a></li>
      </ul>
      <p>
      <button onClick={handleLogout}>Logout</button> {/* Logout button */}      </p>
    </div>
  );
};

export default LandingPage;
